import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.ePeAWSvT.js";const c=JSON.parse('{"title":"Data Adaptation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/datahub-data-adaptation.md","filePath":"guide/datahub-data-adaptation.md"}'),n={name:"guide/datahub-data-adaptation.md"};function i(s,t,d,l,h,u){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="data-adaptation" tabindex="-1">Data Adaptation <a class="header-anchor" href="#data-adaptation" aria-label="Permalink to &quot;Data Adaptation&quot;">​</a></h1><p>There are ways to adapt the data being read or written by the <a href="./reference-common-model.html">Common Model</a>. For example, if one system displays data as a decimal number, but you want the data to show as a monetary value, you can transform that data as the Common Model reads and/or writes it. Adapting data is more likely to be done on the subscribing side, but it is possible to execute on both.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>Only available adaptation options will be displayed based on your configured Endpoints and Mapping Actions.</p></div><h2 id="advanced-tab" tabindex="-1">Advanced Tab <a class="header-anchor" href="#advanced-tab" aria-label="Permalink to &quot;Advanced Tab&quot;">​</a></h2><p>In the advanced settings, you can dictate when data gets transferred from the Common Model to other systems. For instance, on the subscribing side, you may want some functionality to only execute when a new record is created or only when data is updated. Also, data taken from the Common Model that is a string, but needs to be written to a Connector as a double or decimal value, changing the output, can be done here.</p><h3 id="read-action" tabindex="-1">Read Action <a class="header-anchor" href="#read-action" aria-label="Permalink to &quot;Read Action&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>FK System Override</strong></td><td>When the data that is read from the Connector creates a Foreign Key on the Schema, it will by default set the system of Connector. This override allows you to override the key as a value from another system.</td></tr></tbody></table><h3 id="write-action" tabindex="-1">Write Action <a class="header-anchor" href="#write-action" aria-label="Permalink to &quot;Write Action&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>FK System Override</strong></td><td>When the data is written to the Connector, it will by default pull the Foreign Key value of the Connector it is writing to. This override allows you to override the key as a value from another system.</td></tr><tr><td><strong>Supported Operations</strong></td><td>By default, the map will execute for both Create and Updates; however, Supported Operations allows you to direct the map to only execute on a specific Write Operation, Create or Update.</td></tr><tr><td><strong>Value Type</strong></td><td>Allows you to format the data for a given type numeric, date, etc.</td></tr><tr><td><strong>Supported Systems</strong></td><td>By default, the map will execute for any system that posts a message that this Connector receives; however, Supported Systems allow you to only execute this map if the message came from a specific list of systems.</td></tr><tr><td><strong>FK Use Label</strong></td><td>By default, the Foreign Key map writes the value of the Foreign Key; however, this setting allows you to override the default and instead use the Label of the Foreign Key that is stored inside the Central Index.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Users should implement the <strong>Supported Systems</strong> functionality infrequently and only in necessary instances, as this will isolate the data transfer to that specific Mapping.</p></div><h2 id="transforms-tab" tabindex="-1">Transforms Tab <a class="header-anchor" href="#transforms-tab" aria-label="Permalink to &quot;Transforms Tab&quot;">​</a></h2><p>Transforms can be added to either subscribe or publish Mapping; however, they are more commonly used to modify the data being consumed by a system (on the subscribe side). Transforms can be strung together to manipulate data in multiple ways.</p><table tabindex="0"><thead><tr><th>Transform</th><th>Description</th><th>Inputs</th></tr></thead><tbody><tr><td><strong>Addition</strong></td><td>Adds a value to a property on the Schema and outputs the result.</td><td>Add -- the value to be added</td></tr><tr><td><strong>Autonumber Children</strong></td><td>Generates a unique identifier for each child on a message (starts at 1, 2, and so on).</td><td>None (only used on primary key maps)</td></tr><tr><td><strong>Business Logic Map</strong></td><td>Adds conditional logic to a single property. Within a BizLogicMap, you can add Groups for more complex scenarios, where you can achieve And/Or scenarios, but between groups it supports only Or. For example, if the property value equals X or the property value equals Y, then return Z.</td><td>Group: And/Or, Operator, Value, Return Value. Else Return Value: If all of the groups return false, this value is returned from the map.</td></tr><tr><td><strong>Business Logic Map -- Simple</strong></td><td>Adds conditional logic to a single property. This is the same concept as BizLogicMap, but only matches for equality and does not allow for more complex logic with groupings (e.g. if equals this value then return that value).</td><td>Comparison: The value you are comparing the property to be equivalent to; then Return: If the value of the property equals the value of the Comparison, then return this value. Return Null, Return Original Value, Else Return Value.</td></tr><tr><td><strong>Compute Expression</strong></td><td>This transform can be used to take in multiple properties and perform conditional logic or computation and return a value. Uses the syntax for <a href="https://learn.microsoft.com/en-us/dotnet/fundamentals/runtime-libraries/system-data-datacolumn-expression" target="_blank" rel="noreferrer">.NET DataTable.Compute</a>.</td><td>Expression</td></tr><tr><td><strong>Convert from Base64</strong></td><td>Used to convert a property from a Base64 encoded string, typically in file upload scenarios.</td><td>None</td></tr><tr><td><strong>Convert UTC to TimeZone</strong></td><td>Used to convert a date time that is in UTC format to a specific time zone, most likely on a subscriber.</td><td>Time Zone</td></tr><tr><td><strong>Csv To List</strong></td><td>A single property that is a character delimited list of values, split into a List. This transform will only work when mapping into values on the Common Model that is a list of strings.</td><td>Make Distinct, Trim Items, Character Separator</td></tr><tr><td><strong>Default To Current Date</strong></td><td>If the incoming property value is null, it will default to UTC date/time. Typically used on saves for a create record.</td><td>None</td></tr><tr><td><strong>Default Value</strong></td><td>If the incoming property value is null, it will default to this value. Typically used on saves for a create record.</td><td>A predetermined value</td></tr><tr><td><strong>Division</strong></td><td>Takes a property on the Schema and divides by a value; then, outputs the result.</td><td>A Divisor (the value of what you are dividing by)</td></tr><tr><td><strong>Flatten Date/Time</strong></td><td>Used to break a date apart into individual properties on a Save, or to combine them on a Read. For example: <code>{ &quot;year&quot;: 2023, &quot;month&quot;: 1, &quot;day&quot;: 1 }</code></td><td>Include Time, Protocol, Year, Month, Day</td></tr><tr><td><strong>Formatting Template</strong></td><td>Takes one to many properties on the Schema and does a string format; then, returns the result. The format of the template uses placeholders like <code>{0}-{1}-{2}</code>. The mapping engine replaces <code>{0}</code> with the value of the first property, and so on.</td><td>Template</td></tr><tr><td><strong>JSON Contains</strong></td><td>Executes a JSONPath. If it finds a value, it returns <em>true</em>, else returns <em>false</em>.</td><td>JSONPath</td></tr><tr><td><strong>Math Truncate</strong></td><td>Trims off all decimal values.</td><td>None</td></tr><tr><td><strong>Multiplication</strong></td><td>Multiplies a value to a property on the Schema and outputs the result.</td><td>Multiplier (the value to be multiplied)</td></tr><tr><td><strong>Parse to JSON</strong></td><td>Takes a string value and generates a JSON object.</td><td>None</td></tr><tr><td><strong>Regex Match</strong></td><td>Pulls a value out of a string based on a pattern; returns text from within a string that matches the provided regular expression. Only the matching text will be used in the map (to find specific text within a string, such as a specifically formatted date that you want to pull just the month).</td><td>Match Pattern</td></tr><tr><td><strong>Regex Replace</strong></td><td>Formats a string of digits into a specific format; for example, formatting 10 digits into a specific phone number format.</td><td>Match Pattern: tells it what to find in the string. Replace Pattern: tells it how to reformat the string based on what has matched.</td></tr><tr><td><strong>Round</strong></td><td>Applies rounding on a numeric property.</td><td>Behavior: Always round up, Always round down, Default. Precision.</td></tr><tr><td><strong>String Join</strong></td><td>Takes multiple values from a Publisher and writes them as a single, delimited string to the Subscriber.</td><td>Delimiter</td></tr><tr><td><strong>Substring</strong></td><td>Retrieves a portion of a string. For example, if a field can only accept 30 characters, Substring can be used to return only the first 30 characters of a property and remove the rest.</td><td>Starting Index: the position on the string you want to start with (e.g. the starting position is 0). Number of Characters.</td></tr><tr><td><strong>Subtraction</strong></td><td>Subtracts a value from a property on the Schema and outputs the result.</td><td>Subtract -- the value being subtracted</td></tr></tbody></table><h2 id="behaviors-tab" tabindex="-1">Behaviors Tab <a class="header-anchor" href="#behaviors-tab" aria-label="Permalink to &quot;Behaviors Tab&quot;">​</a></h2><p>Behaviors are advanced level options to assist developers in further isolating data transfers. They are unique overrides, used to adapt the data so that it behaves differently than it typically would.</p><table tabindex="0"><thead><tr><th>Behavior</th><th>Description</th></tr></thead><tbody><tr><td><strong>Allow Empty Fixed Value</strong></td><td>Used primarily on Write Maps, it sets empty string on a field that we do not have mapped, but that needs to be included on the payload of a Save.</td></tr><tr><td><strong>Bi-Directional Blocking Identifier</strong></td><td>Used to select a field separate from the key that is unique and can be used to enforce bi-directional blocking on bi-directional endpoints.</td></tr><tr><td><strong>Hide From Logging</strong></td><td>Used to hide sensitive data (SSN, salaries, etc.) from the logs.</td></tr><tr><td><strong>Allow Primary Key to Change</strong></td><td>Used primarily on Read Maps to tell the engine it can update a value on a Primary Key in the Central Index. By default, Central prevents this from happening, so this acts as an override.</td></tr><tr><td><strong>Map from Absolute Root</strong></td><td>Used primarily on Read Maps, and mainly inside of nested maps, to path to the top level.</td></tr><tr><td><strong>Map To Absolute Root</strong></td><td>Used in nested lists to retrieve a value from the parent.</td></tr><tr><td><strong>Skip if Null</strong></td><td>Used primarily on Write maps, in instances where you want to ignore the map entirely if the incoming value on the property is null.</td></tr></tbody></table><h2 id="overrides" tabindex="-1">Overrides <a class="header-anchor" href="#overrides" aria-label="Permalink to &quot;Overrides&quot;">​</a></h2><p>Overrides allow you to define different connector properties based on operations (Create vs Update). For example, you may want a different mapping behavior on creating a new record vs. updating an existing record.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./datahub-action-mapping.html">Action Mapping</a> — Map endpoint actions to the Common Model</li><li><a href="./datahub-endpoint-config.html">Endpoint Configuration</a> — Configure endpoint action inputs and parameterization</li><li><a href="./datahub-endpoint-settings.html">Endpoint Settings</a> — Configure processing behavior for endpoints</li><li><a href="./session-values.html">Session Values</a> — Extract and reuse values across multi-step API workflows</li></ul>',20)])])}const m=e(n,[["render",i]]);export{c as __pageData,m as default};
